/**
 * @summary Verify Facebook webhook
 */
export const getVerifyWebhookUrl = (params?: VerifyWebhookParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/webhook?${stringifiedParams}`
    : `/api/webhook`;
};

export const verifyWebhook = async (
  params?: VerifyWebhookParams,
  options?: RequestInit,
): Promise<string> => {
  return customFetch<string>(getVerifyWebhookUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getVerifyWebhookQueryKey = (params?: VerifyWebhookParams) => {
  return [`/api/webhook`, ...(params ? [params] : [])] as const;
};

export const getVerifyWebhookQueryOptions = <
  TData = Awaited<ReturnType<typeof verifyWebhook>>,
  TError = ErrorType<unknown>,
>(
  params?: VerifyWebhookParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof verifyWebhook>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getVerifyWebhookQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof verifyWebhook>>> = ({
    signal,
  }) => verifyWebhook(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof verifyWebhook>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type VerifyWebhookQueryResult = NonNullable<
  Awaited<ReturnType<typeof verifyWebhook>>
>;
export type VerifyWebhookQueryError = ErrorType<unknown>;

